CREATE OR REPLACE FUNCTION fpa_lon_count_reqno_ym ( ai_year integer,ai_month integer) RETURNS integer AS $body$
DECLARE

  li_count integer;

BEGIN
  select count(loan_requestment_no) into STRICT li_count
  from sc_lon_m_loan_request
  where (extract(year from requestment_date) = ai_year)
  and (extract(month from requestment_date) = ai_month);
  return li_count;
exception when others then CALL spa_dberror('fpa_lon_count_reqno_ym');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
